import React, { useState, useEffect } from "react";
import { useParams, useLocation, Link } from "react-router-dom";

import Header from "../components/common/Header";
import Navbar from "../components/common/Navbar";
import Footer from "../components/common/Footer";
import ProductCard from "../components/product/ProductCard";
import { productAPI, categoryAPI } from "../api";

const ProductList = () => {
  const { slug } = useParams();
  const location = useLocation();
  const queryParams = new URLSearchParams(location.search);

  const searchQuery = queryParams.get("q");
  const categoryQuery = queryParams.get("category");

  const [products, setProducts] = useState([]);
  const [categoryName, setCategoryName] = useState("");
  const [category, setCategory] = useState(null);

  const [sortOrder, setSortOrder] = useState("default");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalProducts, setTotalProducts] = useState(0);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // Khi slug / search / category thay đổi → reset về trang 1
  useEffect(() => {
    setCurrentPage(1);
  }, [slug, searchQuery, categoryQuery]);

  // Fetch sản phẩm khi các tham số thay đổi
  useEffect(() => {
    fetchProducts();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [slug, searchQuery, categoryQuery, currentPage]);

  // =============================
  //  HÀM LẤY SẢN PHẨM
  // =============================
  const fetchProducts = async () => {
    try {
      setLoading(true);
      setError("");

      let response;

      // 1️⃣ Trường hợp có search hoặc lọc category qua query
      if (searchQuery || categoryQuery) {
        response = await productAPI.searchProducts({
          keyword: searchQuery || "",
          category: categoryQuery || "all",
          page: currentPage,
        });

        if (response.data) {
          const productsData = response.data.products || [];
          setProducts(productsData);
          setTotalPages(response.data.pages || 1);
          setTotalProducts(
            response.data.total ||
              response.data.count ||
              productsData.length
          );

          let displayName = "Kết quả tìm kiếm";

          if (searchQuery && categoryQuery && categoryQuery !== "all") {
            displayName = `Tìm "${searchQuery}" trong danh mục "${categoryQuery}"`;
          } else if (searchQuery) {
            displayName = `Kết quả cho "${searchQuery}"`;
          } else if (categoryQuery && categoryQuery !== "all") {
            displayName = `Danh mục: ${categoryQuery}`;
          } else {
            displayName = "Tất cả sản phẩm";
          }

          setCategoryName(displayName);
          setCategory(null);
        }
      }
      // 2️⃣ Trường hợp có slug category trên URL: /category/:slug
      else if (slug) {
        response = await categoryAPI.getProductsByCategory(slug, currentPage);

        if (response.data) {
          const productsData = response.data.products || [];
          setProducts(productsData);
          setCategory(response.data.category || null);
          setCategoryName(
            response.data.category?.name || "Danh mục sản phẩm"
          );
          setTotalPages(response.data.pages || 1);
          setTotalProducts(
            response.data.total ||
              response.data.count ||
              productsData.length
          );
        }
      }
      // 3️⃣ Mặc định: lấy tất cả sản phẩm
      else {
        response = await productAPI.getProducts("", currentPage);

        if (response.data) {
          const productsData = response.data.products || [];
          setProducts(productsData);
          setCategory(null);
          setCategoryName("Tất cả sản phẩm");
          setTotalPages(response.data.pages || 1);
          setTotalProducts(
            response.data.total ||
              response.data.count ||
              productsData.length
          );
        }
      }

      setLoading(false);
    } catch (err) {
      console.error("❌ Lỗi tải sản phẩm:", err);
      let errorMessage = "Không thể tải sản phẩm. Vui lòng thử lại sau.";

      if (err.response) {
        errorMessage =
          err.response.data?.message ||
          `Lỗi ${err.response.status}: Không thể tải sản phẩm.`;
      } else if (err.request) {
        errorMessage =
          "Không thể kết nối đến server. Vui lòng kiểm tra kết nối mạng.";
      } else {
        errorMessage = err.message;
      }

      setError(errorMessage);
      setLoading(false);
    }
  };

  // =============================
  //  SẮP XẾP SẢN PHẨM
  // =============================
  const sortedProducts = [...products].sort((a, b) => {
    switch (sortOrder) {
      case "price-asc": {
        const priceA = a.discountPrice || a.price || 0;
        const priceB = b.discountPrice || b.price || 0;
        return priceA - priceB;
      }
      case "price-desc": {
        const priceA2 = a.discountPrice || a.price || 0;
        const priceB2 = b.discountPrice || b.price || 0;
        return priceB2 - priceA2;
      }
      case "name-asc":
        return (a.name || "").localeCompare(b.name || "", "vi");
      case "name-desc":
        return (b.name || "").localeCompare(a.name || "", "vi");
      case "newest":
        return new Date(b.createdAt || 0) - new Date(a.createdAt || 0);
      default:
        return 0;
    }
  });

  // =============================
  //  UI: LOADING / ERROR
  // =============================
  if (loading) {
    return (
      <div className="flex flex-col min-h-screen bg-[#fff7f9]">
        <Header />
        <Navbar />
        <main className="flex-1 flex items-center justify-center px-4">
          <div className="bg-white rounded-2xl shadow-md border border-pink-100 px-8 py-6 text-center">
            <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-[#e06c7f] mx-auto mb-4" />
            <p className="text-[#4b2c35]">Đang tải sản phẩm...</p>
            {searchQuery && (
              <p className="text-xs text-gray-500 mt-2">
                Từ khóa: <span className="font-medium">"{searchQuery}"</span>
              </p>
            )}
          </div>
        </main>
        
        <Footer />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col min-h-screen bg-[#fff]">
        <Header />
        <Navbar />
        <main className="flex-1 px-4 py-8 max-w-6xl mx-auto">
          <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-5 rounded-2xl shadow-sm">
            <h3 className="font-bold mb-1">Lỗi tải dữ liệu</h3>
            <p className="mb-4 text-sm">{error}</p>
            <button
              onClick={fetchProducts}
              className="inline-flex items-center px-4 py-2 rounded-full bg-red-500 text-white text-sm font-semibold hover:bg-red-600 transition"
            >
              Thử tải lại
            </button>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  // =============================
  //  UI CHÍNH – SHOWROOM STYLE C
  // =============================
  return (
    <div className="flex flex-col min-h-screen bg-[#fff7f9]">
      <Header />
      <Navbar />

      <main className="flex-1 px-4 py-8 max-w-6xl mx-auto">
        {/* Breadcrumb */}
        <div className="mb-4 text-xs text-gray-500">
          <span className="hover:text-[#e06c7f]">
            <Link to="/">Trang chủ</Link>
          </span>{" "}
          /{" "}
          <span className="hover:text-[#e06c7f]">
            <Link to="/products">Sản phẩm</Link>
          </span>{" "}
          {categoryName && (
            <>
              {" "}
              / <span className="text-[#e06c7f] font-medium">{categoryName}</span>
            </>
          )}
        </div>

        {/* TIÊU ĐỀ + TỔNG QUAN */}
        <section className="mb-6">
          <h1 className="text-2xl md:text-3xl font-bold text-[#4b2c35] mb-2">
            {categoryName || "Bộ sưu tập hoa"}
          </h1>
          <p className="text-sm text-gray-600">
            Tìm thấy{" "}
            <span className="font-semibold text-[#e06c7f]">
              {totalProducts || products.length}
            </span>{" "}
            sản phẩm
            {totalPages > 1 && (
              <>
                {" "}
                · Trang{" "}
                <span className="font-semibold">
                  {currentPage}/{totalPages}
                </span>
              </>
            )}
          </p>
          {category?.description && (
            <p className="mt-3 text-sm text-gray-700 max-w-3xl">
              {category.description}
            </p>
          )}
        </section>

        {/* THANH BỘ LỌC & SẮP XẾP – SHOWROOM STYLE */}
        <section className="mb-6">
          <div className="bg-white border border-pink-100 rounded-2xl shadow-sm px-4 py-3 flex flex-col md:flex-row md:items-center md:justify-between gap-3">
            <div className="text-xs md:text-sm text-gray-500">
              Đang hiển thị{" "}
              <span className="font-semibold text-[#4b2c35]">
                {sortedProducts.length}
              </span>{" "}
              sản phẩm trên trang này
              {searchQuery && (
                <span className="ml-1">
                  (từ khóa{" "}
                  <span className="font-medium">"{searchQuery}"</span>)
                </span>
              )}
            </div>

            <div className="flex items-center gap-2 text-sm">
              <span className="text-gray-600">Sắp xếp theo:</span>
              <select
                value={sortOrder}
                onChange={(e) => setSortOrder(e.target.value)}
                className="px-3 py-2 rounded-full border border-pink-200 bg-white text-sm outline-none focus:ring-2 focus:ring-[#e06c7f]"
              >
                <option value="default">Mặc định</option>
                <option value="newest">Mới nhất</option>
                <option value="price-asc">Giá: Thấp → Cao</option>
                <option value="price-desc">Giá: Cao → Thấp</option>
                <option value="name-asc">Tên: A → Z</option>
                <option value="name-desc">Tên: Z → A</option>
              </select>
            </div>
          </div>
        </section>

        {/* GRID SẢN PHẨM – SHOWROOM CARD */}
        {sortedProducts.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-md border border-pink-100 py-16 px-6 text-center">
            <div className="text-5xl mb-3">🔍</div>
            <h2 className="text-xl font-semibold text-[#4b2c35] mb-2">
              Không tìm thấy sản phẩm phù hợp
            </h2>
            <p className="text-sm text-gray-600 mb-4">
              {searchQuery ? (
                <>
                  Không có sản phẩm nào cho từ khóa{" "}
                  <span className="font-semibold">"{searchQuery}"</span>.
                </>
              ) : (
                "Hiện chưa có sản phẩm nào trong danh mục này."
              )}
            </p>
            <p className="text-xs text-gray-400 mb-3">Gợi ý:</p>
            <ul className="text-xs text-gray-500 space-y-1 mb-6">
              <li>• Kiểm tra lại chính tả từ khóa.</li>
              <li>• Thử dùng từ khóa chung hơn (ví dụ: “hoa hồng”).</li>
              <li>• Thử quay lại xem tất cả sản phẩm.</li>
            </ul>

            <div className="flex flex-wrap gap-3 justify-center">
              <button
                onClick={() => window.history.back()}
                className="px-5 py-2 rounded-full border border-pink-200 text-sm text-[#4b2c35] hover:bg-[#fff0f5] transition"
              >
                ⬅ Quay lại
              </button>
              <Link
                to="/products"
                className="px-5 py-2 rounded-full bg-[#e06c7f] text-white text-sm font-semibold hover:bg-[#cc5f72] transition"
              >
                Xem tất cả sản phẩm
              </Link>
            </div>
          </div>
        ) : (
          <>
            {/* GRID */}
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-5 md:gap-6">
              {sortedProducts.map((product) => (
                <ProductCard key={product._id} product={product} />
              ))}
            </div>

            {/* PHÂN TRANG */}
            {totalPages > 1 && (
              <div className="flex justify-center mt-10">
                <div className="flex items-center gap-2 bg-white border border-pink-100 rounded-full px-3 py-2 shadow-sm">
                  {currentPage > 1 && (
                    <button
                      onClick={() => setCurrentPage(currentPage - 1)}
                      className="px-3 py-1 rounded-full text-xs border border-pink-200 hover:bg-[#fff0f5] text-[#4b2c35]"
                    >
                      ← Trước
                    </button>
                  )}

                  {Array.from(
                    { length: Math.min(5, totalPages) },
                    (_, i) => {
                      const page =
                        currentPage <= 3 ? i + 1 : currentPage - 2 + i;
                      if (page > totalPages) return null;
                      return (
                        <button
                          key={page}
                          onClick={() => setCurrentPage(page)}
                          className={`px-3 py-1 rounded-full text-xs border transition ${
                            currentPage === page
                              ? "bg-[#e06c7f] text-white border-[#e06c7f]"
                              : "border-pink-200 text-[#4b2c35] hover:bg-[#fff0f5]"
                          }`}
                        >
                          {page}
                        </button>
                      );
                    }
                  )}

                  {currentPage < totalPages && (
                    <button
                      onClick={() => setCurrentPage(currentPage + 1)}
                      className="px-3 py-1 rounded-full text-xs border border-pink-200 hover:bg-[#fff0f5] text-[#4b2c35]"
                    >
                      Sau →
                    </button>
                  )}
                </div>
              </div>
            )}
          </>
        )}
      </main>

      <Footer />
    </div>
  );
};

export default ProductList;
